        blocks: [
          { type: "p", text: "Role of the School" },
          { type: "list", items: ["Provides opportunities for learning multiple languages.", "Ensures availability of teachers and resources to support language development.", "Offers ongoing professional development for educators to enhance skills and competencies.", "Identifies students needing additional language support and provides targeted interventions.", "Supports parents of first-generation learners by communicating in their home language, where possible.", "Plans curriculum, inquiry trails, and parent meetings to ensure no community member is excluded due to language barriers.", "Celebrates linguistic diversity through class activities, assemblies, and cultural events, nurturing pride in home languages and the host country’s language."] },
          { type: "p", text: "Role of the Library" },
          { type: "list", items: ["Provides resources that support academic requirements and student interests.", "Encourages students to use the library for research, reading, and issuing books.", "Facilitates literary events and celebrations in collaboration with language teachers.", "Promotes a strong reading culture through programmes for both students and staff.", "Library committee considers student and teacher preferences when adding new resources."] },
          { type: "p", text: "Role of Teachers and Staff" },
          { type: "list", items: ["At DPS New Chandigarh, all teachers are language teachers , embedding language learning across subjects.", "Teachers model clear, confident, and accurate language use.", "Integrate subject-specific academic vocabulary in lessons.", "Strengthen communication skills through purposeful speaking, listening, reading, and writing.", "Plan student-centred activities that promote dialogue, reasoning, and collaboration.", "Provide scaffolding, structured tasks, and guided practice to ensure student success.", "Differentiate instruction to meet diverse language needs, including additional support in English.", "Select resources that uphold equality, diversity, inclusion, and academic rigour.", "Receive regular training in phonics, early literacy, inquiry-based strategies, differentiation, and EAL methodologies.", "Co-plan with the English lead to integrate subject-specific vocabulary.", "Library staff support teachers and students with appropriate book selection, multilingual resources, and promoting reading culture."] },
          { type: "p", text: "Role of Parents and Community" },
          { type: "list", items: ["Act as active partners in children’s language growth.", "Maintain a positive attitude towards the use of mother tongue, especially in early years.", "Read with children in English or home language and reinforce phonics and vocabulary practice.", "Attend curriculum familiarisation meetings to understand the school’s languagephilosophy.", "Support consistency with chosen language options and maintain communication with the school for additional support.", "Partner with local libraries, cultural associations, and storytellers to create authentic language experiences.", "Volunteer as storytellers to share cultural narratives in home languages."] },
          { type: "p", text: "Role of Students" },
          { type: "list", items: ["Communicate in English inside and outside the classroom, except during lessons for other languages.", "Show respect towards peers who may speak with home language influence.", "Listen to presentations, watch age-appropriate media, and explore digital content in the target language."] },
          { type: "p", text: "Read texts and literature in English and other languages to strengthen comprehension and linguistic awareness." },
        ],
